#!/usr/bin/perl -w

use strict;
use warnings;
use DBI;
use CGI qw(:standard);


# Set the database connection information here.
my $dbuser = 'root'; # Your MySQL username goes here.
my $dbpass = '';     # Your MySQL password goes here.
my $dbname = 'users';  # The name of your MySQL database goes here.
my $dbhost = 'localhost'; # The hostname of the MySQL server goes here.

# Connect to the MySQL database using DBI and the information above.
my $dbh = DBI->connect("DBI:mysql:database=$dbname;host=$dbhost", $dbuser, $dbpass);


# Get the username from the CGI parameter "username".
my $username = param('username');

# Get the password from the CGI parameter "password".
my $password = param('password');

if (defined($username) && defined($password)) {
    # Build a SQL query with string interpolation.
    my $sql = 'SELECT * FROM users WHERE username=\'$username\' AND password=\'<PASSWORD>\';';

    # Run the query and fetch the results as an array of hashes.
    my @results = $dbh->selectall_arrayref($sql);

    if (@results) {
        print "Welcome, $username!\n";
        print "<a href=\"/\">Logout</a>";
    } else {
        print "Incorrect username or password.\n";
        print "<form method=\"post\" action=\"login.cgi\">\n";
        print "\tUsername: <input type=\"text\" name=\"username\"><br>\n";
        print "\tPassword: <input type=\"password\" name=\"password\"><br><br>\n";
        print "\t<input type=\"submit\" value=\"Login\">";
    }
} else {
    # If the CGI parameters are not set, show login form.
    print "<form method=\"post\" action=\"login.cgi\">\n";
    print "\tUsername: <input type=\"text\" name=\"username\"><br>\n";
